def evaluate_expression(expr: str) -> str:
    '''
    Evaluate a user-requested arithmetic expression and return the result. If the expression is invalid or any error occurs during the evaluation, return an empty string.

    Args:
        expr (str): The user-requested arithmetic expression to evaluate.

    Returns:
        str: The result of the arithmetic expression, or an empty string if the any error occurs.
    '''
    try:
        # Validate that expr is a string
        if not isinstance(expr, str):
            return ""

        # Strip whitespace
        expr = expr.strip()

        # Check if expression is empty
        if not expr:
            return ""

        # Only allow safe characters: digits, operators, parentheses, and decimal point
        allowed_chars = set("0123456789+-*/.() ")
        if not all(c in allowed_chars for c in expr):
            return ""

        # Prevent multiple operators in a row (except for unary minus/plus)
        # This helps prevent some injection attempts
        import re

        # Check for invalid patterns like -- or ** or // etc (except in valid contexts)
        # Allow unary operators at start or after opening paren or after operators
        if re.search(r'[+\-*/]\s*[+\-*/]', expr):
            # Check if it's a valid unary operator case
            if not re.search(r'[\(]\s*[+\-]', expr) and not re.match(r'^[+\-]', expr):
                return ""

        # Check for empty parentheses
        if "()" in expr:
            return ""

        # Use ast.literal_eval with a restricted namespace for safety
        # Actually, we'll use eval with a restricted namespace
        result = eval(expr, {"__builtins__": {}}, {})

        # Validate result is a number
        if not isinstance(result, (int, float)):
            return ""

        # Handle infinity and NaN
        if isinstance(result, float):
            if result != result:  # NaN check
                return ""
            if result == float('inf') or result == float('-inf'):
                return ""

        # Return result as string
        # Format to remove unnecessary decimals
        if isinstance(result, float):
            if result.is_integer():
                return str(int(result))
            else:
                return str(result)
        else:
            return str(result)

    except (SyntaxError, ValueError, TypeError, ZeroDivisionError, NameError, AttributeError):
        return ""
    except Exception:
        return ""
